import ClubOverview from "./ClubOverview";
import ClubNews from "./ClubNews";
import ClubMembers from "./club-tabs/ClubMembers";
import ClubStats from "./club-tabs/ClubStats";

export default function ClubMain({
                                     tab = "overview",
                                     club,
                                     members = [],
                                     news = [],
                                     isLeader = false,
                                     user
                                 }) {
    // ⛑️ HARD GUARD — prevents runtime crash
    if (!club) {
        return <div style={{ padding: 20 }}>Loading club…</div>;
    }

    const TAB_MAP = {
        overview: ClubOverview,
        news: ClubNews,
        members: ClubMembers,
        stats: ClubStats
    };

    // ✅ SAFE DEFAULT — works even if backend has no enabledTabs
    const enabledTabs = Array.isArray(club.enabledTabs)
        ? club.enabledTabs
        : ["overview", "news", "members"];

    if (!enabledTabs.includes(tab)) {
        return (
            <div style={{ padding: 20, color: "#b00020" }}>
                This section is not available for this club.
            </div>
        );
    }

    const ActiveTab = TAB_MAP[tab] || ClubOverview;

    return (
        <div style={{ padding: 20 }}>
            <ActiveTab
                club={club}
                members={members}
                news={news}
                isLeader={isLeader}
                user={user}
            />
        </div>
    );
}
